// GMeshServer is the server API for GMesh service.
// All implementations must embed UnimplementedGMeshServer
// for forward compatibility.
//
// GMesh is the control-plane API exposed by the gmeshd daemon over a Unix
// socket. The GritivaCore agent, gmeshctl, and any other local process talks
// to gmeshd through this service.
//
// All mutating RPCs are idempotent on the {peer_id, mesh_ip} primary key.
type GMeshServer interface {
	// ── Lifecycle ─────────────────────────────────────────────────────────
	Join(context.Context, *JoinRequest) (*JoinResponse, error)
	Leave(context.Context, *LeaveRequest) (*LeaveResponse, error)
	Status(context.Context, *StatusRequest) (*StatusResponse, error)
	Version(context.Context, *VersionRequest) (*VersionResponse, error)
	// ── Peers ─────────────────────────────────────────────────────────────
	AddPeer(context.Context, *AddPeerRequest) (*AddPeerResponse, error)
	RemovePeer(context.Context, *RemovePeerRequest) (*RemovePeerResponse, error)
	UpdatePeer(context.Context, *UpdatePeerRequest) (*UpdatePeerResponse, error)
	ListPeers(context.Context, *ListPeersRequest) (*ListPeersResponse, error)
	GetPeerStats(context.Context, *GetPeerStatsRequest) (*GetPeerStatsResponse, error)
	// ── NAT & traversal ───────────────────────────────────────────────────
	DiscoverNAT(context.Context, *DiscoverNATRequest) (*DiscoverNATResponse, error)
	HolePunch(context.Context, *HolePunchRequest) (*HolePunchResponse, error)
	// ── Relay / WS tunnel ─────────────────────────────────────────────────
	SetupRelay(context.Context, *SetupRelayRequest) (*SetupRelayResponse, error)
	AllocateWSTunnel(context.Context, *AllocateWSTunnelRequest) (*AllocateWSTunnelResponse, error)
	// ── Health ────────────────────────────────────────────────────────────
	HealthCheck(context.Context, *HealthCheckRequest) (*HealthCheckResponse, error)
	// ── Scopes (netns-isolated peers behind a VM) ─────────────────────────
	ScopeConnect(context.Context, *ScopeConnectRequest) (*ScopeConnectResponse, error)
	ScopeDisconnect(context.Context, *ScopeDisconnectRequest) (*ScopeDisconnectResponse, error)
	// ── Firewall (nftables) ───────────────────────────────────────────────
	ApplyFirewall(context.Context, *ApplyFirewallRequest) (*ApplyFirewallResponse, error)
	ResetFirewall(context.Context, *ResetFirewallRequest) (*ResetFirewallResponse, error)
	GetFirewallStatus(context.Context, *GetFirewallStatusRequest) (*GetFirewallStatusResponse, error)
	// ── Event stream ──────────────────────────────────────────────────────
	// Server-streaming RPC. Subscribers get async events: peer state changes,
	// NAT re-discovery, health degradation, firewall apply results, etc.
	SubscribeEvents(*SubscribeEventsRequest, grpc.ServerStreamingServer[Event]) error
	// ── Egress profiles (Phase 11) ────────────────────────────────────────
	// An egress profile routes selected outbound traffic through a specific
	// mesh peer acting as an "exit node" instead of the local default gateway.
	CreateEgressProfile(context.Context, *CreateEgressProfileRequest) (*EgressProfileResponse, error)
	UpdateEgressProfile(context.Context, *UpdateEgressProfileRequest) (*EgressProfileResponse, error)
	DeleteEgressProfile(context.Context, *DeleteEgressProfileRequest) (*DeleteEgressProfileResponse, error)
	ListEgressProfiles(context.Context, *ListEgressProfilesRequest) (*ListEgressProfilesResponse, error)
	// Exit-side operations: called on the peer that acts as an exit node.
	// EnableExit installs MASQUERADE + FORWARD rules so forwarded traffic
	// egresses correctly; DisableExit tears them down.
	EnableExit(context.Context, *EnableExitRequest) (*EnableExitResponse, error)
	DisableExit(context.Context, *DisableExitRequest) (*DisableExitResponse, error)
	// ── Ingress profiles (Phase 12) ───────────────────────────────────────
	// Expose a backend service (running on another mesh peer, optionally
	// inside a scope netns) on the edge peer's public address via nftables
	// DNAT. Inbound packets are tunneled over the mesh to the backend.
	CreateIngressProfile(context.Context, *CreateIngressProfileRequest) (*IngressProfileResponse, error)
	UpdateIngressProfile(context.Context, *UpdateIngressProfileRequest) (*IngressProfileResponse, error)
	DeleteIngressProfile(context.Context, *DeleteIngressProfileRequest) (*DeleteIngressProfileResponse, error)
	ListIngressProfiles(context.Context, *ListIngressProfilesRequest) (*ListIngressProfilesResponse, error)
	// ── Quotas (Phase 13) ────────────────────────────────────────────────
	// Byte-counter-driven policy attached to an EgressProfile. Emits events
	// when thresholds are crossed; optionally swaps traffic to a backup
	// profile automatically at the shift threshold.
	CreateQuota(context.Context, *CreateQuotaRequest) (*QuotaResponse, error)
	UpdateQuota(context.Context, *UpdateQuotaRequest) (*QuotaResponse, error)
	DeleteQuota(context.Context, *DeleteQuotaRequest) (*DeleteQuotaResponse, error)
	ListQuotas(context.Context, *ListQuotasRequest) (*ListQuotasResponse, error)
	GetQuotaUsage(context.Context, *GetQuotaUsageRequest) (*GetQuotaUsageResponse, error)
	ResetQuota(context.Context, *ResetQuotaRequest) (*ResetQuotaResponse, error)
	mustEmbedUnimplementedGMeshServer()
}

